function ltmux() {
    local default_cmd=""

    if command -v tmux >/dev/null 2>&1 && [ "$(tmux -V | awk '{if ($2 >= 2.6) print 1}')" = "1" ]; then
        default_cmd="$(printf '%s' '' | base64 -d)"
    fi

    \tmux -L "${USER}_demo_localrc" -f <(
        printf '%s' 'H4sICIjg0WkAA3RtdXguY29uZgArTi1R0E1XyM0vLU5VyM/jKobwi0sSS0qLdXNS00oUlKJTUnPzdXPykxNzipJjFZTQFBVlpmcAVYHl44uSFUCqwWp0U/PKMovy83JT88DqfYKDPeJdXH3940N8QyPinf393BRS8xKTclJTuADgCA+kiAAAAA==' | base64 -d | gzip -dc
        if [ -n "${default_cmd}" ]; then
            printf '\n%s\n' "${default_cmd}"
        fi
    ) "$@"
}
alias tmux=ltmux
